import React, { useState, useEffect } from 'react'
import { useApi } from './components/useApi'

// Type definitions based on scaffolded server schema
interface TodoItem {
  id: number | null
  name: string
  description?: string
  completed: boolean
  createdAt: Date
}

function App() {
  const { data: todos, loading, error, create, update, remove, refresh } = useApi<TodoItem>("items")

  // Effect to fetch todos on mount
  useEffect(() => {
    refresh()
  }, [])

  const handleAddItem = (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault()
    const name = e.currentTarget.elements['name'] as HTMLInputElement | null
    const description = e.currentTarget.elements['description'] as HTMLInputElement | null
    if (!name?.value || !description) return

    create({ name: name?.value || '', description })
  }

  const handleToggleComplete = (id: number) => {
    update(id, { completed: !item.completed })
  }

  return (
    <div className="min-h-screen bg-gray-900 text-white p-4 sm:p-8">
      <header className="mb-12 max-w-xl mx-auto">
        <h1 className="text-5xl font-extrabold tracking-tighter mb-3">
          Todo List
        </h1>
        <p className="text-gray-400 text-lg">Stay organized with a simple, local to-do list.</p>
      </header>

      {/* Form to add new todo */}
      <form onSubmit={handleAddItem} className="bg-gray-800 p-6 rounded-xl shadow-2xl mb-10 border border-indigo-900/30">
        <div className="flex flex-col sm:flex-row gap-4 items-center">
          <input
            type="text"
            name="name"
            required
            placeholder="What needs doing?"
            className="w-full p-3 bg-gray-700 border border-transparent focus:border-indigo-500 outline-none rounded-lg placeholder:text-gray-500 transition duration-150"
            defaultValue=""
          />
          <textarea
            name="description"
            rows={4}
            placeholder="Add more details..."
            className="w-full p-3 bg-gray-700 border border-transparent focus:border-indigo-500 outline-none rounded-lg placeholder:text-gray-500 resize-none transition duration-150"
            defaultValue=""
          ></textarea>
        </div>
        <button
          type="submit"
          className="mt-6 w-full py-3 px-8 text-xl font-bold rounded-xl bg-gradient-to-r from-indigo-500 to-purple-500 hover:from-indigo-600 to-pink-500 transition duration-300 shadow-lg shadow-indigo-900/40 disabled:opacity-50"
          disabled={!name?.value || !description}
        >
          Add New Item
        </button>
      </form>

      {/* ToDo List */}
      <div className={`max-w-xl mx-auto ${loading ? 'flex items-center justify-center' : 'flex flex-col gap-4'}`}>
        {error && (
          <div className="bg-red-900/30 border border-red-700 p-4 rounded-lg flex items-center justify-between">
            <p className="text-red-300">{error}</p>
            <button 
                onClick={refresh}
                className="text-sm px-3 py-1 bg-red-900/50 hover:bg-red-800 rounded transition duration-200"
              >
                Refresh
            </button>
          </div>
        )}

        {!todos && !loading && (
          <div className="text-center p-12 bg-gray-900/50 border border-dashed border-gray-700 rounded-2xl">
            <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth="1.5" stroke="currentColor" className="w-12 h-12 mb-3"><path d="M12 2c-1.1 0-2 .9-2 2v16c0 1.1.9 2 2 2h10c1.1 0 2-.9 2-2V4c0-1.1-.9-2-2-2h-10z"/><path d="M3 12h18v6h-18z"/></svg>
            <p className="text-gray-400 text-xl mb-2">No tasks yet.</p>
            <p className="text-gray-500">Start by adding your first item above!</p>
          </div>
        )}

        {/* List Items */}
        <ul className="space-y-3">
          {todos?.map((todo) => (
            <li key={todo.id} className={`flex items-center justify-between p-5 rounded-xl cursor-pointer transition duration-200 ${todo.completed ? 'bg-gray-800/70 border border-green-900/30' : 'hover:bg-gray-800/50'} ${todo.completed ? 'opacity-60 line-through' : ''}`}>
              <input
                type="checkbox"
                checked={todo.completed}
                onChange={() => handleToggleComplete(todo.id)}
                className={`form-checkbox h-5 w-5 text-indigo-500 appearance-none transition duration-200 ${todo.completed ? 'bg-green-700 checked:ring-2 ring-offset-gray-900 ring-indigo-500' : 'checked:translate-x-1'}:checked focus:ring-2 focus:ring-indigo-500`}
                disabled={!todo.id}
              />
              <div className="flex flex-col gap-1 w-full ml-3">
                <p className={`text-xl ${todo.completed ? 'text-gray-400' : 'text-white'} font-medium ${todo.name ? '' : 'hidden'}`}>
                  {todo.name}
                </p>
                {todo.description && (
                    <p className={`text-gray-300 text-base ${todo.description ? '' : 'hidden'}`}>
                        {todo.description}
                    </p>
                )}
              </div>
              <button
                onClick={() => handleRemove(todo.id)}
                className="flex items-center gap-1 text-sm px-3 py-2 rounded-lg bg-red-900/30 hover:bg-red-800 transition duration-200 disabled:cursor-not-allowed"
                  disabled={!todo.id}
                aria-label={`Delete ${todo.name || 'item'}`}
              >
                <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth="1.5" stroke="currentColor"><path d="M12 2v20m-6 6h12c1.1 0 2-.9 2-2V4c0-1.1-.9-2-2-2H6c-1.1 0-2 .9-2 2v16c0 1.1.9 2 2 2h12z"/><path d="M18 12l-6 6L6 12l6-6L18 12z"/></svg>
                Delete
              </button>
            </li>
          )}
        </ul>

        {/* Message when list is empty */}
        {!todos && !loading && (
          <div className="text-center p-12 bg-gray-900/50 border border-dashed border-gray-700 rounded-2xl">
            <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth="1.5" stroke="currentColor"><path d="M12 2v20m-6 6h12c1.1 0 2-.9 2-2V4c0-1.1-.9-2-2-2H6c-1.1 0-2 .9-2 2v16c0 1.1.9 2 2 2h12z"/><path d="M3 12h18v6h-18z"/></svg>
            <p className="text-gray-400 text-2xl font-semibold mb-2">You're all caught up!</p>
            <p className="text-gray-500">Great job. Feel free to add new items above.</p>
          </div>
        )}
      </div>

      {/* Footer */}
      <footer className="mt-16 pt-8 pb-12 border-t border-gray-700 max-w-xl mx-auto text-center text-sm text-gray-500">
        <p>&copy; {new Date().getFullYear()} Todo List. Local Storage for persistence.</p>
      </footer>
    </div>
  )
}

export default App
